SELECT acceptor_name
FROM electron_acceptors
WHERE standard_potential = (SELECT MAX(standard_potential) FROM electron_acceptors);

SELECT type, products, AVG(standard_potential) AS avg_standard_potential
FROM metabolic_processes
GROUP BY type, products;

SELECT type, products, standard_potential
FROM metabolic_processes
WHERE standard_potential > 0.00;

SELECT "type", "standard_potential"
FROM metabolic_processes
ORDER BY "standard_potential" DESC;

SELECT type, standard_potential
FROM metabolic_processes
WHERE standard_potential = (SELECT MAX(standard_potential) FROM metabolic_processes);

SELECT acceptor_name, standard_potential
FROM electron_acceptors
ORDER BY standard_potential DESC;

SELECT title
FROM research_studies
WHERE date_conducted = (SELECT MAX(date_conducted) FROM research_studies);
